```plantuml
@startuml
class Kategorie {
    +id: int
    +bezeichnung: String
}

class HotelzimmerKategorie {
    +hotelZimmer: Hotelzimmer
    +kategorie: Kategorie
}

class Hotelzimmer {
    +nummer: int
    +personen: int
}

class Buchung {
    +hotelZimmer: Hotelzimmer
    +gast: Gast
    +anreiseDatum: LocalDate
    +abreiseDatum: LocalDate
}

class Gast {
    +kundenNr: int
    +name: String
    +adresse: Adresse
}

class LeistungspaketBuchung {
    +leistungspaket: Leistungspaket
    +buchung: Buchung
    +anzahl: int
}

class Leistungspaket {
    +bezeichnung: String
    +preis: BigDecimal
}

class LeistungspaketBetreuer {
    +leistungspaket: Leistungspaket
    +betreuer: Betreuer
}

class Luxuspaketpaket {
    +bezeichnung: String
    +leistungspaket: Leistungspaket
}

class Mitarbeiter {
    +svnr: String
    +name: String
    +adresse: String
}

class HotelzimmerMitarbeiter {
    +hotelZimmer: HotelzimmerMitarbeiter
    +mitarbeiter: Mitarbeiter
    +hotelZimmer: Hotelzimmer
    +mitarbeiter: Mitarbeiter
    +datum: LocalDate
}

class Betreuer {
    +mitarbeiter: Mitarbeiter
    +fach: String
}

HotelzimmerKategorie ..> Hotelzimmer : "1"
HotelzimmerKategorie ..> Kategorie : "*"
Hotelzimmer --* Buchung : "*"
Buchung --* Gast : "*"
LeistungspaketBuchung --* Leistungspaket : "*"
LeistungspaketBuchung --* Buchung : "*"
Leistungspaket ..> LeistungspaketBetreuer : "*"
Leistungspaket ..> Luxuspaketpaket : "1"
Luxuspaketpaket ..> Leistungspaket : "*"
note right of Luxuspaketpaket: ein Luxuspaketpaket hat mehrere Einträge mit der gleichen Bezeichnung
Mitarbeiter <|-- Betreuer
HotelzimmerMitarbeiter --* Mitarbeiter : "*"
HotelzimmerMitarbeiter --* Hotelzimmer : "*"

@enduml
```
